module priority_encoder (
    input [3:0] obf_in,
    output reg [1:0] out
);

    always @(*) begin
        if (obf_in[3]) begin
            out = 2'b11;
        end else if (obf_in[2]) begin
            out = 2'b10;
        end else if (obf_in[1]) begin
            out = 2'b01;
        end else if (obf_in[0]) begin
            out = 2'b00;
        end else begin
            out = 2'b00;
        end
    end
endmodule
